SELECT (value->>'id')::text, value, now()
FROM jsonb_array_elements('[{"id":"newton-stacey-sp11","name":"Newton Stacey","village":"Newton Stacey","town":"Andover","county":"Hampshire","postcode":"SP11","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Andover","coords":{"lat":51.18764,"lng":-1.50756},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":null,"overview":"Newton Stacey is a hamlet of around fifty households in the civil parish of Barton Stacey, in the Test Valley district, set on the south bank of the River Dever roughly one and a half miles west of Barton Stacey village and four and a half miles south-west of the railway town of Andover. The hamlet lies between the A303 (a mile to the north) and the A30 (a mile to the south) on lanes that cross both trunk roads, giving an unusually quick exit east to Winchester or west to Stockbridge. The seed CSV tags this record SP11 but the Royal Mail post town is Stockbridge and Newton Stacey''s actual postcode area is SO20 (residential addresses sit in SO20 6BP and nearby sectors); the Wikipedia infobox confirms SO20. Historically the hamlet''s most-cited resident is the 17th-century preacher Stephen Bachiler, whose zealous followers from Newton Stacey settled in New England. The 2012 closure of the Newton Stacey post office means daily-need shopping is now at Barton Stacey or Andover.","character":"Tiny linear hamlet of detached cottages, period farmhouses and a small number of modern infill plots, set in arable chalkland with the Dever as a southern boundary. No village centre and no formal conservation-area designation. Building stock includes brick, flint and rendered cottages alongside larger 20th-century houses.","amenities":["Newton Stacey ford on the River Dever","Access to Bransbury Common SSSI (south-east)","Direct lane access to Barton Stacey amenities (1.5 mi)","Close to Naomi House Children''s Hospice at Sutton Scotney (~3 mi)"],"schools":[{"name":"Barton Stacey Church of England Primary School","phase":"Primary","ofsted":null,"distance":"1.6 mi","url":"https://reports.ofsted.gov.uk/"},{"name":"The Swan Inn / Barton Stacey village amenities","phase":"Amenity","ofsted":null,"distance":"1.5 mi","url":"https://www.bartonstacey.org.uk/"},{"name":"Test Valley School / Danebury School, Stockbridge","phase":"Secondary","ofsted":"Inadequate (2022)","distance":"5.0 mi","url":"https://reports.ofsted.gov.uk/"}],"transport":{"commutes":[{"to":"London Waterloo","time":"1h 10m","mode":"drive to Andover + direct train (South Western Railway)","source":"https://www.thetrainline.com/train-times/andover-to-london-waterloo"},{"to":"London Waterloo (fastest)","time":"1h 2m","mode":"drive + train","source":"https://www.thetrainline.com/train-times/andover-to-london-waterloo"},{"to":"Winchester (by road)","time":"~20m","mode":"drive (A30 / A33)","source":"https://www.nationalrail.co.uk/"}],"nearestStation":"Andover (5.0 mi)","roads":"A303 ~1 mi (Bransbury junction); A30 ~1 mi; A34 (Sutton Scotney) ~2 mi"},"prices":{"avgSold12Mo":null,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so20.html","asOf":"2026-05"},"thingsToDo":["Walking Bransbury Common SSSI","Dever and Test footpaths to Barton Stacey","Naomi House and Jacksplace open days (~3 mi)","Hampshire CC Wherwell-to-Chilbolton riverside trail (~4 mi)","Sutton Scotney village shops and Tarrant''s farm shop (~3 mi)"],"placesToEat":[{"name":"The Swan Inn, Barton Stacey","type":"Village pub","notes":"Closest pub; 1.5 mi east in Barton Stacey","url":"https://www.useyourlocal.com/"}],"pros":["Quick A303 / A30 / A34 access in three directions","Andover station 5 mi for direct Waterloo trains in 1h 2-10m","Bransbury Common SSSI within walking distance","Period and modern stock available at lower prices than Stockbridge or Wherwell"],"cons":["Seed CSV tags this record SP11; the real postcode area is SO20","No shop, pub, school or church within the hamlet itself","Secondary catchment school rated Inadequate in 2022","A303 traffic noise audible from northern lanes"],"whoItSuits":"Buyers wanting a quieter and cheaper alternative to Stockbridge or Wherwell, accepting that the hamlet has no in-village amenities and that day-to-day life is oriented to Barton Stacey, Sutton Scotney or Andover. Particularly suited to remote workers needing fast trunk-road access (A303 east-west, A34 north-south) and to families willing to drive children to Barton Stacey Primary. Not appropriate for buyers needing public transport, a village school in walking distance, or in-village social anchor like a pub.","broadbandMedianMbps":null,"nearestStation":"Andover (5.0 mi)","primarySupermarket":"Sainsbury''s, Andover (5.5 mi); Waitrose, Stockbridge (5.5 mi)","images":[],"sources":["https://en.wikipedia.org/wiki/Newton_Stacey","https://en.wikipedia.org/wiki/Barton_Stacey","https://getoutside.ordnancesurvey.co.uk/local/newton-stacey-test-valley","https://mapcarta.com/N1272258398","https://www.thetrainline.com/train-times/andover-to-london-waterloo","https://www.testvalley.gov.uk/benefitsandcounciltax/counciltax/council-tax-charges"]},{"id":"newtown-sp5","name":"Newtown","village":"Newtown","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":50.98808,"lng":-1.8696},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"northington-so24","name":"Northington","village":"Northington","town":"Winchester","county":"Hampshire","postcode":"SO24","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.07556,"lng":-1.15364},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"nunton-sp5","name":"Nunton","village":"Nunton","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.0158,"lng":-1.85508},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"odstock-sp5","name":"Odstock","village":"Odstock","town":"Salisbury","county":"Wiltshire","postcode":"SP5","hubCity":"Salisbury","regionDir":"","settlementType":"","subRegion":"Salisbury","coords":{"lat":51.01668,"lng":-1.86484},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"old-alresford-so24","name":"Old Alresford","village":"Old Alresford","town":"Winchester","county":"Hampshire","postcode":"SO24","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.08052,"lng":-1.15124},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"otterbourne-so21","name":"Otterbourne","village":"Otterbourne","town":"Winchester","county":"Hampshire","postcode":"SO21","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.05968,"lng":-1.29364},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"over-wallop-so20","name":"Over Wallop","village":"Over Wallop","town":"Andover","county":"Hampshire","postcode":"SO20","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Andover","coords":{"lat":51.127,"lng":-1.50896},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"researched","priceSummary":null,"councilTaxBand":"D","overview":"Over Wallop is the westernmost of The Wallops — three contiguous villages strung along the chalk-stream Wallop Brook — and the source of the Brook itself, which rises in the parish and flows south-east to join the River Test below Bossington. The village sits in the Test Valley district immediately adjacent to the Wiltshire border, approximately five miles north-west of Stockbridge and seven miles south-west of Andover. It is named in Domesday as ''the other Wallop'' — distinguishing it from Nether Wallop, the larger of the original pair. The 12th-century parish church of St Peter (Diocese of Winchester) anchors the southern end of the village; Victorian restorations are visible. Archaeology runs deep: flint mines in the parish date to roughly 3,983 BC, and the Quarley High Linear earthwork to around 245 BC. The Wallops share two pubs, a village hall, a Good village primary at Nether Wallop, a veterinary surgery and a shop with post office. Over Wallop has its own Conservation Area designation and an active Neighbourhood Development Plan (adopted 2022) focused on resisting excessive housing development.","character":"Loose linear village along chalk lanes with timber-framed and brick-and-flint cottages, plus a number of 20th-century additions. Working agricultural village rather than show village; population around 1,000 across the parish. The Brook frames the conservation area and is the social spine.","amenities":["St Peter''s Church (12th century)","The White Hart (Over Wallop village pub)","Wallops shop with Post Office (Nether Wallop)","Wallops Parish Hall (Middle Wallop)","Veterinary surgery (shared Wallops)","Cricket club","Active Neighbourhood Development Plan","Wallop Brook source (parish)"],"schools":[{"name":"Wallop Primary School (Nether Wallop)","phase":"Primary","ofsted":"Good","distance":"1.5 mi","url":"https://files.ofsted.gov.uk/v1/file/50221039"},{"name":"Test Valley School / Danebury School, Stockbridge","phase":"Secondary","ofsted":"Inadequate (2022)","distance":"6.5 mi","url":"https://reports.ofsted.gov.uk/"}],"transport":{"commutes":[{"to":"London Waterloo (via Grateley)","time":"~1h 20m","mode":"drive + train (SWR West of England line)","source":"https://www.nationalrail.co.uk/"},{"to":"London Waterloo (via Andover, fastest)","time":"1h 2m","mode":"drive + train","source":"https://www.thetrainline.com/train-times/andover-to-london-waterloo"},{"to":"Salisbury","time":"~25m","mode":"drive (A343 / A30)","source":"https://www.nationalrail.co.uk/"}],"nearestStation":"Grateley (3.0 mi)","roads":"A343 ~1 mi; A30 (Stockbridge) ~5 mi; A303 ~3 mi"},"prices":{"avgSold12Mo":null,"avgDetached":null,"avgSemi":null,"avgTerraced":null,"avgFlat":null,"source":"https://www.rightmove.co.uk/house-prices/so20.html","asOf":"2026-05"},"thingsToDo":["Walking the Wallop Brook Way (4.7-mile route)","St Peter''s Church visit","Quarley High Linear earthwork (~2 mi)","Army Flying Museum (1.5 mi at Middle Wallop)","Salisbury cathedral and market (12 mi)","Annual Over Wallop village fête"],"placesToEat":[{"name":"The White Hart, Over Wallop","type":"Village pub","notes":"Traditional Wallops freehouse with food","url":"https://www.useyourlocal.com/"},{"name":"The George Inn, Middle Wallop","type":"Village pub","notes":"1.5 mi east in Middle Wallop","url":"https://www.useyourlocal.com/"}],"pros":["Wallop Primary (Good) shared across all three Wallops villages","Quietest of the Wallops — furthest from the A343 and AAC airfield noise","Grateley station 3 mi for Waterloo trains via SWR West of England line","Strong neighbourhood plan protecting rural character"],"cons":["Wiltshire-border position means some council services are split with Wiltshire CC","Secondary catchment school rated Inadequate in 2022","AAC airfield helicopter noise audible across the parish","Limited evening transport; pub closure or shop turnover hurts daily life"],"whoItSuits":"Buyers wanting the chalk-stream Test Valley character at slightly lower prices than Stockbridge proper, with a Good village primary and decent train access via either Grateley or Andover. Quieter than Middle Wallop because further from the airfield, but the helicopters are still audible. Best fit for families with primary-age children, service-family households on Middle Wallop posting wanting some buffer from the airfield, and downsizers from Stockbridge or Salisbury. The Wiltshire-border position means some practical services (utility providers, county-specific schemes) need cross-county checks.","broadbandMedianMbps":null,"nearestStation":"Grateley (3.0 mi)","primarySupermarket":"Waitrose, Stockbridge (5.0 mi); Sainsbury''s, Andover (7.0 mi)","images":[],"sources":["https://en.wikipedia.org/wiki/Over_Wallop","https://over-wallop.parish.uk/","https://www.british-history.ac.uk/vch/hants/vol4/pp530-535","https://hwwhite.co.uk/salisbury/the-wallops/","https://owparishndp.uk/wp-content/uploads/2021/04/History-part-1-2.pdf","https://files.ofsted.gov.uk/v1/file/50221039","https://www.thetrainline.com/train-times/andover-to-london-waterloo","https://www.testvalley.gov.uk/benefitsandcounciltax/counciltax/council-tax-charges"]},{"id":"ovington-so24","name":"Ovington","village":"Ovington","town":"Winchester","county":"Hampshire","postcode":"SO24","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.08712,"lng":-1.17352},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]},{"id":"owlsbury-so21","name":"Owlsbury","village":"Owlsbury","town":"Winchester","county":"Hampshire","postcode":"SO21","hubCity":"Southampton","regionDir":"North","settlementType":"Non-City","subRegion":"Winchester","coords":{"lat":51.08284,"lng":-1.31848},"coordsSource":"postcode-outward-approx","houseTypeIds":[],"status":"directory","priceSummary":null,"councilTaxBand":null,"overview":"","character":"","amenities":[],"schools":[],"transport":{"commutes":[]},"prices":{},"thingsToDo":[],"placesToEat":[],"pros":[],"cons":[],"whoItSuits":[],"broadbandMedianMbps":null,"nearestStation":null,"primarySupermarket":null,"images":[],"sources":[]}]'::jsonb) AS value
